tasks.description:
Write Playwright UAT tests verifying the bot can execute ALL admin CRUD actions via conversation.

Create `tests/playwright/uat/bot-crud.spec.ts`:

```typescript
test.describe('Bot CRUD UAT — Admin Operations', () => {
  // Login + open bot before each

  test('create commodity via bot', async ({ page }) => {
    const reply = await sendBotMessage(page, 'create commodity rice grain kg');
    expect.soft(reply).toMatch(/created|rice|commodity/i);
  });

  test('create instrument via bot', async ({ page }) => {
    const reply = await sendBotMessage(page, 'create instrument rice-futures RIC-2027M07 rice jul 2027 contract 5000 tick 0.01');
    expect.soft(reply).toMatch(/created|instrument|RIC/i);
  });

  test('list instruments shows new instrument', async ({ page }) => {
    const reply = await sendBotMessage(page, 'show instruments');
    expect.soft(reply).toMatch(/WHT|instrument/i);
  });

  test('set participant tier via bot', async ({ page }) => {
    const reply = await sendBotMessage(page, 'set tier farmer for trader1');
    expect.soft(reply).toMatch(/tier|farmer|updated/i);
  });

  test('register warehouse facility via bot', async ({ page }) => {
    const reply = await sendBotMessage(page, 'register facility UB Grain Storage');
    expect.soft(reply).toMatch(/facility|registered|warehouse/i);
  });

  test('issue warehouse receipt via bot', async ({ page }) => {
    const reply = await sendBotMessage(page, 'issue receipt farmer1 wheat 5000 bushels');
    expect.soft(reply).toMatch(/receipt|issued|warehouse/i);
  });

  test('screen participant via bot', async ({ page }) => {
    const reply = await sendBotMessage(page, 'screen participant trader1');
    expect.soft(reply).toMatch(/screen|clear|result/i);
  });

  test('submit order via bot', async ({ page }) => {
    const reply = await sendBotMessage(page, 'buy 10 wheat at 325');
    expect.soft(reply).toMatch(/order|submitted|buy|placed/i);
  });

  test('halt and resume via bot', async ({ page }) => {
    const halt = await sendBotMessage(page, 'halt wheat');
    expect.soft(halt).toMatch(/halt|stopped|WHT/i);
    const resume = await sendBotMessage(page, 'resume wheat');
    expect.soft(resume).toMatch(/resume|started|WHT/i);
  });

  test('approve KYC via bot', async ({ page }) => {
    const reply = await sendBotMessage(page, 'show pending KYC');
    expect.soft(reply).toMatch(/participant|pending|application|0/i);
  });

  test('file SAR via bot', async ({ page }) => {
    const reply = await sendBotMessage(page, 'file SAR on trader1 for suspicious trading');
    expect.soft(reply).toMatch(/sar|filed|suspicious/i);
  });

  test('generate report via bot', async ({ page }) => {
    const reply = await sendBotMessage(page, 'market summary today');
    expect.soft(reply).toMatch(/market|summary|report/i);
  });

  test('show audit log via bot', async ({ page }) => {
    const reply = await sendBotMessage(page, 'show audit log');
    expect.soft(reply).toMatch(/audit|trail|log/i);
  });

  test('create ticket via bot', async ({ page }) => {
    const reply = await sendBotMessage(page, 'report a bug: the margin page loads slowly');
    expect.soft(reply).toMatch(/ticket|created|bug|report/i);
  });

  test('bot help lists ALL command categories', async ({ page }) => {
    const reply = await sendBotMessage(page, 'help');
    // Must list all admin domains
    expect.soft(reply).toMatch(/instrument/i);
    expect.soft(reply).toMatch(/commodity/i);
    expect.soft(reply).toMatch(/fee/i);
    expect.soft(reply).toMatch(/warehouse/i);
    expect.soft(reply).toMatch(/margin/i);
    expect.soft(reply).toMatch(/settlement/i);
    expect.soft(reply).toMatch(/compliance|alert/i);
    expect.soft(reply).toMatch(/order/i);
    expect.soft(reply).toMatch(/ticket/i);
  });
});
```

15+ tests covering ALL admin CRUD operations via bot.

Acceptance: All tests pass against live portal. Bot executes every admin action.
